INSERT INTO public.exercises (external_id,name,muscle_group,secondary_muscles,equipment,category,instructions,description,image_url,source,is_public) VALUES ('Incline_Push-Up_Reverse_Grip','Incline Push-Up Reverse Grip','pecho',ARRAY['abdominales','hombros','tríceps'],'peso corporal','strength',ARRAY['Stand facing a Smith machine bar or sturdy elevated platform at an appropriate height.','Place your hands on the bar palms up, with your hands about shoulder width apart.','Position your feet back from the bar with arms and body straight. This will be your starting position.','Keeping your body straight, lower your chest to the bar by bending the arms.','Return to the starting position by extending the elbows, pressing yourself back up.'],'Stand facing a Smith machine bar or sturdy elevated platform at an appropriate height. Place your hands on the bar palms up, with your hands about shoulder width apart. Position your feet back from the bar with arms and body straight. This will be your starting position. Keeping your body straight, lower your chest to the bar by bending the arms. Return to the starting position by extending the elbows, pressing yourself back up.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Incline_Push-Up_Reverse_Grip/0.jpg','exercisedb',true),('Incline_Push-Up_Wide','Incline Push-Up Wide','pecho',ARRAY['abdominales','hombros','tríceps'],'peso corporal','strength',ARRAY['Stand facing a Smith machine bar or sturdy elevated platform at an appropriate height.','Place your hands on the bar, with your hands wider than shoulder width.','Position your feet back from the bar with arms and body straight. Your arms should be perpendicular to the body. This will be your starting position.','Keeping your body straight, lower your chest to the bar by bending the arms.','Return to the starting position by extending the elbows, pressing yourself back up.'],'Stand facing a Smith machine bar or sturdy elevated platform at an appropriate height. Place your hands on the bar, with your hands wider than shoulder width. Position your feet back from the bar with arms and body straight. Your arms should be perpendicular to the body. This will be your starting position. Keeping your body straight, lower your chest to the bar by bending the arms. Return to the starting position by extending the elbows, pressing yourself back up.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Incline_Push-Up_Wide/0.jpg','exercisedb',true),('Intermediate_Groin_Stretch','Intermediate Groin Stretch','isquiotibiales',ARRAY[]::text[],'otro','stretching',ARRAY['Lie on your back with your legs extended. Loop a belt, rope, or band around one of your feet, and swing that leg as far to the side as you can. This will be your starting position.','Pull gently on the belt to create tension in your groin and hamstring muscles. Hold for 10-20 seconds, and repeat on the other side.'],'Lie on your back with your legs extended. Loop a belt, rope, or band around one of your feet, and swing that leg as far to the side as you can. This will be your starting position. Pull gently on the belt to create tension in your groin and hamstring muscles. Hold for 10-20 seconds, and repeat on the other side.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Intermediate_Groin_Stretch/0.jpg','exercisedb',true),('Intermediate_Hip_Flexor_and_Quad_Stretch','Intermediate Hip Flexor and Quad Stretch','cuádriceps',ARRAY[]::text[],'otro','stretching',ARRAY['Lie face down on the floor, with a rope, belt, or band looped around one foot.','Flex the knee and extend the hip of the leg to be stretched, using both hands to pull on the belt. Your knee and your hip should come off of the floor, creating tension in the hip flexors and quadriceps. Hold the stretch for 10-20 seconds, and repeat on the other leg.'],'Lie face down on the floor, with a rope, belt, or band looped around one foot. Flex the knee and extend the hip of the leg to be stretched, using both hands to pull on the belt. Your knee and your hip should come off of the floor, creating tension in the hip flexors and quadriceps. Hold the stretch for 10-20 seconds, and repeat on the other leg.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Intermediate_Hip_Flexor_and_Quad_Stretch/0.jpg','exercisedb',true),('Internal_Rotation_with_Band','Internal Rotation with Band','hombros',ARRAY[]::text[],'bandas elásticas','strength',ARRAY['Choke the band around a post. The band should be at the same height as your elbow. Stand with your right side to the band a couple of feet away.','Grasp the end of the band with your right hand, and keep your elbow pressed firmly to your side. We recommend you hold a pad or foam roll in place with your elbow to keep it firmly in position.','With your upper arm in position, your elbow should be flexed to 90 degrees with your hand reaching away from your torso. This will be your starting position.','Execute the movement by rotating your arm in a forehand motion, keeping your elbow in place.','Continue as far as you are able, pause, and then return to the starting position.'],'Choke the band around a post. The band should be at the same height as your elbow. Stand with your right side to the band a couple of feet away. Grasp the end of the band with your right hand, and keep your elbow pressed firmly to your side. We recommend you hold a pad or foam roll in place with your elbow to keep it firmly in position. With your upper arm in position, your elbow should be flexed to 90 degrees with your hand reaching away from your torso. This will be your starting position. Execute the movement by rotating your arm in a forehand motion, keeping your elbow in place. Continue as far as you are able, pause, and then return to the starting position.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Internal_Rotation_with_Band/0.jpg','exercisedb',true),('Inverted_Row','Inverted Row','espalda media',ARRAY['dorsales'],NULL,'strength',ARRAY['Position a bar in a rack to about waist height. You can also use a smith machine.','Take a wider than shoulder width grip on the bar and position yourself hanging underneath the bar. Your body should be straight with your heels on the ground with your arms fully extended. This will be your starting position.','Begin by flexing the elbow, pulling your chest towards the bar. Retract your shoulder blades as you perform the movement.','Pause at the top of the motion, and return yourself to the start position.','Repeat for the desired number of repetitions.'],'Position a bar in a rack to about waist height. You can also use a smith machine. Take a wider than shoulder width grip on the bar and position yourself hanging underneath the bar. Your body should be straight with your heels on the ground with your arms fully extended. This will be your starting position. Begin by flexing the elbow, pulling your chest towards the bar. Retract your shoulder blades as you perform the movement. Pause at the top of the motion, and return yourself to the start position. Repeat for the desired number of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Inverted_Row/0.jpg','exercisedb',true),('Inverted_Row_with_Straps','Inverted Row with Straps','espalda media',ARRAY['bíceps','dorsales'],'otro','strength',ARRAY['Hang a rope or suspension straps from a rack or other stable object. Grasp the ends and position yourself in a supine position hanging from the ropes. Your body should be straight with your heels on the ground with your arms fully extended. This will be your starting position.','Begin by flexing the elbow, pulling your chest to your hands. Retract your shoulder blades as you perform the movement.','Pause at the top of the motion, and return yourself to the start position.','Repeat for the desired number of repetitions.'],'Hang a rope or suspension straps from a rack or other stable object. Grasp the ends and position yourself in a supine position hanging from the ropes. Your body should be straight with your heels on the ground with your arms fully extended. This will be your starting position. Begin by flexing the elbow, pulling your chest to your hands. Retract your shoulder blades as you perform the movement. Pause at the top of the motion, and return yourself to the start position. Repeat for the desired number of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Inverted_Row_with_Straps/0.jpg','exercisedb',true),('Iron_Cross','Iron Cross','hombros',ARRAY['pecho','glúteos','isquiotibiales','espalda baja','cuádriceps','trapecios'],'mancuernas','strength',ARRAY[]::text[],NULL,'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Iron_Cross/0.jpg','exercisedb',true),('Iron_Crosses_stretch','Iron Crosses (stretch)','cuádriceps',ARRAY[]::text[],NULL,'stretching',ARRAY['Lie face down on the floor, with your arms extended out to your side, palms pressed to the floor. This will be your starting position.','To begin, flex one knee and bring that leg across the back of your body, attempting to touch it to the ground near the opposite hand.','Promptly return the leg to the starting postion, and quickly repeat with the other leg. Continue alternating for 10-20 repetitions.'],'Lie face down on the floor, with your arms extended out to your side, palms pressed to the floor. This will be your starting position. To begin, flex one knee and bring that leg across the back of your body, attempting to touch it to the ground near the opposite hand. Promptly return the leg to the starting postion, and quickly repeat with the other leg. Continue alternating for 10-20 repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Iron_Crosses_stretch/0.jpg','exercisedb',true),('Isometric_Chest_Squeezes','Isometric Chest Squeezes','pecho',ARRAY['hombros','tríceps'],'peso corporal','plyometrics',ARRAY['While either seating or standing, bend your arms at a 90-degree angle and place the palms of your hands together in front of your chest. Tip: Your hands should be open with the palms together and fingers facing forward (perpendicular to your torso).','Push both hands against each other as you contract your chest. Start with slow tension and increase slowly. Keep breathing normally as you execute this contraction.','Hold for the recommended number of seconds.','Now release the tension slowly.','Rest for the recommended amount of time and repeat.'],'While either seating or standing, bend your arms at a 90-degree angle and place the palms of your hands together in front of your chest. Tip: Your hands should be open with the palms together and fingers facing forward (perpendicular to your torso). Push both hands against each other as you contract your chest. Start with slow tension and increase slowly. Keep breathing normally as you execute this contraction. Hold for the recommended number of seconds. Now release the tension slowly. Rest for the recommended amount of time and repeat.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Isometric_Chest_Squeezes/0.jpg','exercisedb',true);